# ─── RLC Physics ─────────────────────────────────────────────────────────────
def compute_rlc_response(R, L, C, t_end=0.05, n_points=2000):
    """Compute step response of series RLC circuit."""
    t = np.linspace(0, t_end, n_points)
    omega0 = 1.0 / np.sqrt(L * C)
    alpha  = R / (2 * L)
    zeta   = alpha / omega0

    if zeta < 1.0 - 1e-6:
        # Underdamped
        omega_d = omega0 * np.sqrt(1 - zeta**2)
        v = 1 - np.exp(-alpha * t) * (np.cos(omega_d * t) + (alpha / omega_d) * np.sin(omega_d * t))
        regime = 'underdamped'
    elif zeta > 1.0 + 1e-6:
        # Overdamped
        s1 = -alpha + np.sqrt(alpha**2 - omega0**2)
        s2 = -alpha - np.sqrt(alpha**2 - omega0**2)
        A  =  s2 / (s2 - s1)
        B  = -s1 / (s2 - s1)
        v  = 1 + A * np.exp(s1 * t) + B * np.exp(s2 * t)
        regime = 'overdamped'
    else:
        # Critically damped
        v = 1 - np.exp(-alpha * t) * (1 + alpha * t)
        regime = 'critically_damped'

    v = np.clip(v, -2, 3)
    return t, v, regime, zeta

