# ─── Animation ────────────────────────────────────────────────────────────────
SWEEP_FRAMES = 80
TAIL_LEN = 60

def animate(frame):
    state['pulse_phase'] += 0.016  # ~60fps tick

    # Redraw schematic with glow pulse
    draw_schematic(ax_schem, state['pulse_phase'])

    t_full = state['t']
    v_full = state['v']

    if len(t_full) == 0:
        return

    # Sweep animation
    if state['sweep_active']:
        state['anim_frame'] = min(state['anim_frame'] + 1, SWEEP_FRAMES)
        frac = state['anim_frame'] / SWEEP_FRAMES
        if state['anim_frame'] >= SWEEP_FRAMES:
            state['sweep_active'] = False

        # Fade in regime label
        alpha_label = min(1.0, (state['anim_frame'] - SWEEP_FRAMES * 0.7) / (SWEEP_FRAMES * 0.3))
        regime_text.set_alpha(max(0, alpha_label))
        zeta_text.set_alpha(max(0, alpha_label))
    else:
        frac = 1.0

    n_show = max(2, int(len(t_full) * frac))
    t_show = t_full[:n_show]
    v_show = v_full[:n_show]

    waveform_glow2.set_data(t_show, v_show)
    waveform_glow1.set_data(t_show, v_show)
    waveform_core.set_data(t_show, v_show)

    # Traveling dot at sweep head
    if state['sweep_active'] and n_show > 1:
        dot_t = t_show[-1]
        dot_v = v_show[-1]
        travel_dot.set_data([dot_t], [dot_v])
        tail_start = max(0, n_show - TAIL_LEN)
        travel_tail.set_data(t_show[tail_start:], v_show[tail_start:])
        travel_dot.set_alpha(1.0)
        travel_tail.set_alpha(0.6)
    else:
        travel_dot.set_alpha(0.0)
        travel_tail.set_alpha(0.0)

    return (waveform_glow2, waveform_glow1, waveform_core,
            travel_dot, travel_tail, regime_text, zeta_text)

