# ─── Mouse Hover (Crosshair + Tooltip) ────────────────────────────────────────
def on_mouse_move(event):
    if event.inaxes != ax_osc:
        crosshair_v.set_alpha(0)
        crosshair_h.set_alpha(0)
        tooltip.set_visible(False)
        fig.canvas.draw_idle()
        return

    t_full = state['t']
    v_full = state['v']
    if len(t_full) == 0:
        return

    mx = event.xdata
    if mx is None:
        return

    # Snap to nearest data point
    idx = np.argmin(np.abs(t_full - mx))
    snap_t = t_full[idx]
    snap_v = v_full[idx]

    crosshair_v.set_xdata([snap_t])
    crosshair_v.set_alpha(0.7)
    crosshair_h.set_ydata([snap_v])
    crosshair_h.set_alpha(0.5)

    tooltip.xy = (snap_t, snap_v)
    tooltip.set_text(f't = {snap_t:.3f} ms\nV = {snap_v:.4f} V')
    tooltip.set_visible(True)

    fig.canvas.draw_idle()

fig.canvas.mpl_connect('motion_notify_event', on_mouse_move)

